return $input.all().map(item => {
  const errorObj = item.json || {};
  const errorMsg = errorObj.message || errorObj.error?.description || "Unknown Database Error";
  let severity = "critical";
  let promptContext = "";

  if (errorMsg.includes("Duplicate document") || errorMsg.includes("unique constraint")) {
    severity = "info";
    promptContext = "Idempotency Guard: This exact file was already processed.";
  } else if (errorMsg.includes("Business Duplicate")) {
    severity = "info";
    promptContext = "Business Guard: Invoice number exists for this vendor.";
  } else if (errorMsg.includes("No fingerprint provided")) {
    severity = "warning";
    promptContext = "The workflow failed to generate a fingerprint hash.";
  } else {
    severity = "critical";
    promptContext = "A severe database error occurred.";
  }

  return {
    json: {
      severity,
      raw_error: errorMsg,
      context_for_llm: promptContext,
      timestamp: new Date().toISOString()
    }
  };
});

// 1) Safely extract payload pieces
const input = $input.first().json;
const body = input.body || input;
const message = body.message || {};
const thread = body.thread || {};

const attachments = Array.isArray(message.attachments) ? message.attachments : [];
const messageLabels = Array.isArray(message.labels) ? message.labels : [];
const threadLabels = Array.isArray(thread.labels) ? thread.labels : [];

const allLabels = [...new Set([...messageLabels, ...threadLabels])];

if (attachments.length === 0) {
  return [];
}

return attachments.map((att, index) => {
  const filename = att.filename || '';
  const contentType = att.content_type || '';
  const isPdf =
    contentType.toLowerCase() === 'application/pdf' ||
    contentType.toLowerCase().includes('pdf') ||
    filename.toLowerCase().endsWith('.pdf');

  return {
    json: {
      inbox_id: message.inbox_id || null,
      message_id: message.message_id || null,
      thread_id: message.thread_id || thread.thread_id || null,
      sender: message.from || message.from_ || null,
      subject: message.subject || null,
      preview: message.preview || null,
      created_at: message.created_at || null,
      message_labels: messageLabels,
      thread_labels: threadLabels,
      all_labels: allLabels,
      attachment_id: att.attachment_id || null,
      filename,
      content_type: contentType,
      size: att.size || null,
      content_disposition: att.content_disposition || null,
      content_id: att.content_id || null,
      is_pdf: isPdf,
      attachment_count: attachments.length,
      has_multiple_attachments: attachments.length > 1,
      attachment_index: index,
      attachment_number: index + 1,
      fingerprint: `${message.message_id || 'no_message_id'}_${att.attachment_id || index}`
    }
  };
});

