  let preparedPayload = {};
  let completeResult = data.complete_pipeline_job || data;

  if (typeof completeResult === "string") {
    try {
      completeResult = JSON.parse(completeResult);
    } catch (e) {
      completeResult = {};
    }
  }

  try {
    attachmentId = $('Extract Attachment Payload').first().json.attachment_id;
  } catch (e) {}

  try {
    preparedPayload = $("Prepare Database Data").first().json;
  } catch (e) {}

  return {
    json: {
      source: "n8n",
      workflowName: "SpendBase Inbound",
      nodeName: "✅ Complete Pipeline Job",
      executionId,
      attachmentId,
      fingerprint: preparedPayload.fingerprint || null,
      stage: "db_upsert_succeeded",
      status: "success",
      message: "Invoice processed successfully",
      payload: {
        invoiceNumber: preparedPayload.invoiceNumber || null,
        vendorName: preparedPayload.vendorName || null,
        vendorDomain: preparedPayload.vendorDomain || null,
        totalAmount: preparedPayload.totalAmount || null,
        currency: preparedPayload.currency || null
      },
      context: {
        job_id: completeResult.job_id || null,
        job_key: completeResult.job_key || null,
        final_status: completeResult.final_status || null
      }
    }
  };
});

// 1. Pull absolute arrays from upstream nodes to bypass broken item-linking
const allAcquireResults = $('Parse Acquire Result').all();

// 2. Safely pull current item lineages where available
let guardData = {};
let downloadData = {};
try { guardData = $('Extract Attachment Payload').item.json; } catch(e) {}
try { downloadData = $('Fetch Download URL').item.json; } catch(e) {}

const jigsawData = $input.item.json || {};

// 3. Find the specific Acquire Result for THIS exact attachment
const myAcquireResult = allAcquireResults.find(item => 
  item.json.attachment_id === guardData.attachment_id
)?.json || {};

// 4. Extract Text and Stats from Jigsaw
const cleanSections = (jigsawData.sections || []).map(section => ({
  text: section.text,
  lines: (section.lines || []).map(line => typeof line === 'object' ? (line.text || '') : line).filter(Boolean)
}));
const fullText = cleanSections.map(s => s.text).join('\n');
const confidence = jigsawData.sections?.[0]?.lines?.[0]?.average_confidence || 0;

// 5. Evaluate Booleans
const isInvoiceFlag = jigsawData.context?.isInvoice?.[0] === 'true';
const isPaidFlag = jigsawData.context?.isPaid?.[0] === 'true';

const textLower = fullText.toLowerCase();
const hasInvoiceKeywords = textLower.includes('invoice') || textLower.includes('tax invoice') || textLower.includes('bill to');

// Fallback URL extraction depending on HTTP node output shape
const downloadUrl = downloadData.download_url || downloadData.url || downloadData.body?.download_url || '';

// 6. Return Unified Production Payload
return {
  json: {
    // --- Routing & Decision Logic ---
    shouldProceed: (isInvoiceFlag || hasInvoiceKeywords) && confidence > 0.6,
    isInvoice: isInvoiceFlag || hasInvoiceKeywords,
    isPaid: isPaidFlag,
    confidenceScore: parseFloat(confidence.toFixed(4)),
    isLowConfidence: confidence < 0.85,

    // --- Task & Job Management (FIXED) ---
    acquired: myAcquireResult.acquired === true,
    job_id: myAcquireResult.job_id || null,
    job_key: myAcquireResult.job_key || null,
    acquire_status: myAcquireResult.acquire_status || null,
    acquire_reason: myAcquireResult.acquire_reason || null,
    acquire_attempt_count: myAcquireResult.acquire_attempt_count || null,

    // --- Metadata & Identity ---
    ...guardData, 
    download_url: downloadUrl,
    summaryText: fullText.substring(0, 500),
    fullText: fullText.trim(),
    sections: cleanSections,
    _originalLogId: jigsawData.log_id || guardData.fingerprint || null
  }
};

