CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS trigger LANGUAGE plpgsql AS
$body$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$body$;

CREATE TABLE IF NOT EXISTS public.vendors (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  domain text NULL,
  support_email text NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS vendors_domain_unique_idx
  ON public.vendors (lower(domain)) WHERE domain IS NOT NULL;

CREATE INDEX IF NOT EXISTS vendors_name_idx
  ON public.vendors (name);

DROP TRIGGER IF EXISTS trg_vendors_updated_at ON public.vendors;
CREATE TRIGGER trg_vendors_updated_at
  BEFORE UPDATE ON public.vendors
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE TABLE IF NOT EXISTS public.documents (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  vendor_id uuid NOT NULL REFERENCES public.vendors(id) ON DELETE RESTRICT,
  fingerprint text NOT NULL,
  n8n_execution_id text NULL,
  invoice_number text NULL,
  total_amount numeric(18,6) NOT NULL DEFAULT 0,
  currency char(3) NOT NULL,
  received_at timestamptz NOT NULL,
  raw_payload jsonb NOT NULL DEFAULT '{}'::jsonb,
  llm_extraction_payload jsonb NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS documents_fingerprint_unique_idx
  ON public.documents (fingerprint);

CREATE INDEX IF NOT EXISTS documents_vendor_id_idx ON public.documents (vendor_id);
CREATE INDEX IF NOT EXISTS documents_received_at_idx ON public.documents (received_at DESC);
CREATE INDEX IF NOT EXISTS documents_invoice_number_idx ON public.documents (invoice_number);
CREATE INDEX IF NOT EXISTS documents_currency_idx ON public.documents (currency);

ALTER TABLE public.documents
  DROP CONSTRAINT IF EXISTS documents_currency_check;
ALTER TABLE public.documents
  ADD CONSTRAINT documents_currency_check CHECK (currency ~ '^[A-Z]{3}$');

DROP TRIGGER IF EXISTS trg_documents_updated_at ON public.documents;
CREATE TRIGGER trg_documents_updated_at
  BEFORE UPDATE ON public.documents
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE TABLE IF NOT EXISTS public.line_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  document_id uuid NOT NULL REFERENCES public.documents(id) ON DELETE CASCADE,
  vendor_id uuid NOT NULL REFERENCES public.vendors(id) ON DELETE RESTRICT,
  position integer NOT NULL,
  description text NOT NULL,
  clean_name text NOT NULL,
  billing_type public.billing_type_enum NOT NULL,
  billing_cycle text NULL,
  quantity numeric(18,6) NOT NULL DEFAULT 1,
  unit_price numeric(18,6) NOT NULL DEFAULT 0,
  total_price numeric(18,6) NOT NULL DEFAULT 0,
  currency char(3) NOT NULL,
  period_end date NULL,
  category text NULL,
  original_description text NULL,
  seat_count integer NULL,
  tier text NULL,
  raw_metadata jsonb NOT NULL DEFAULT '{}'::jsonb,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS line_items_document_position_unique_idx
  ON public.line_items (document_id, position);

CREATE INDEX IF NOT EXISTS line_items_document_id_idx ON public.line_items (document_id);
CREATE INDEX IF NOT EXISTS line_items_vendor_id_idx ON public.line_items (vendor_id);
CREATE INDEX IF NOT EXISTS line_items_billing_type_idx ON public.line_items (billing_type);
CREATE INDEX IF NOT EXISTS line_items_billing_cycle_idx ON public.line_items (billing_cycle);
CREATE INDEX IF NOT EXISTS line_items_category_idx ON public.line_items (category);
CREATE INDEX IF NOT EXISTS line_items_period_end_idx ON public.line_items (period_end);

ALTER TABLE public.line_items
  DROP CONSTRAINT IF EXISTS line_items_currency_check;
ALTER TABLE public.line_items
  ADD CONSTRAINT line_items_currency_check CHECK (currency ~ '^[A-Z]{3}$');

ALTER TABLE public.line_items
  DROP CONSTRAINT IF EXISTS line_items_position_check;
ALTER TABLE public.line_items
  ADD CONSTRAINT line_items_position_check CHECK (position >= 0);

DROP TRIGGER IF EXISTS trg_line_items_updated_at ON public.line_items;
CREATE TRIGGER trg_line_items_updated_at
  BEFORE UPDATE ON public.line_items
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE TABLE IF NOT EXISTS public.pipeline_jobs (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  job_key text NOT NULL,
  attachment_id text NULL,
  fingerprint text NULL,
  status text NOT NULL DEFAULT 'pending',
  attempt_count integer NOT NULL DEFAULT 0,
  workflow_name text NULL,
  current_stage text NULL,
  locked_at timestamptz NULL,
  started_at timestamptz NULL,
  finished_at timestamptz NULL,
  last_error text NULL,
  payload jsonb NOT NULL DEFAULT '{}'::jsonb,
  result jsonb NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

DO
$body$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'pipeline_jobs_status_check'
  ) THEN
    ALTER TABLE public.pipeline_jobs ADD CONSTRAINT pipeline_jobs_status_check
      CHECK (status IN ('pending','processing','succeeded','failed','manual_review','skipped'));
  END IF;
END
$body$;

CREATE UNIQUE INDEX IF NOT EXISTS pipeline_jobs_job_key_unique_idx ON public.pipeline_jobs (job_key);
CREATE INDEX IF NOT EXISTS pipeline_jobs_status_idx ON public.pipeline_jobs (status);
CREATE INDEX IF NOT EXISTS pipeline_jobs_attachment_id_idx ON public.pipeline_jobs (attachment_id);
CREATE INDEX IF NOT EXISTS pipeline_jobs_fingerprint_idx ON public.pipeline_jobs (fingerprint);
CREATE INDEX IF NOT EXISTS pipeline_jobs_created_at_idx ON public.pipeline_jobs (created_at DESC);
CREATE INDEX IF NOT EXISTS pipeline_jobs_updated_at_idx ON public.pipeline_jobs (updated_at DESC);
CREATE INDEX IF NOT EXISTS pipeline_jobs_workflow_name_idx ON public.pipeline_jobs (workflow_name);

DROP TRIGGER IF EXISTS trg_pipeline_jobs_updated_at ON public.pipeline_jobs;
CREATE TRIGGER trg_pipeline_jobs_updated_at
  BEFORE UPDATE ON public.pipeline_jobs
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE OR REPLACE FUNCTION public.process_full_invoice(payload jsonb)
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS
$body$
DECLARE
  v_vendor_id uuid;
  v_document_id uuid;
  v_existing_document_id uuid;
  v_vendor_name text;
  v_vendor_domain text;
  v_support_email text;
  v_fingerprint text;
  v_n8n_execution_id text;
  v_invoice_number text;
  v_total_amount numeric;
  v_currency text;
  v_received_at timestamptz;
  v_inserted_items integer := 0;
BEGIN
  IF payload IS NULL THEN RAISE EXCEPTION 'payload is null'; END IF;

  v_fingerprint := nullif(trim(payload->>'fingerprint'), '');
  IF v_fingerprint IS NULL THEN RAISE EXCEPTION 'fingerprint is required'; END IF;

  v_vendor_name := COALESCE(nullif(trim(payload->>'vendorName'), ''), 'Unknown Vendor');
  v_vendor_domain := nullif(lower(trim(payload->>'vendorDomain')), '');
  v_support_email := nullif(trim(payload->>'supportEmail'), '');
  v_n8n_execution_id := nullif(trim(payload->>'n8nExecutionId'), '');
  v_invoice_number := nullif(trim(payload->>'invoiceNumber'), '');
  v_total_amount := COALESCE((payload->>'totalAmount')::numeric, 0);
  v_currency := upper(COALESCE(nullif(trim(payload->>'currency'), ''), 'USD'));
  IF v_currency !~ '^[A-Z]{3}$' THEN v_currency := 'USD'; END IF;
  v_received_at := COALESCE((payload->>'receivedAt')::timestamptz, now());

  IF v_vendor_domain IS NOT NULL THEN
    SELECT id INTO v_vendor_id FROM public.vendors WHERE lower(domain) = v_vendor_domain LIMIT 1;
  END IF;
  IF v_vendor_id IS NULL THEN
    SELECT id INTO v_vendor_id FROM public.vendors
      WHERE domain IS NULL AND lower(name) = lower(v_vendor_name) LIMIT 1;
  END IF;
  IF v_vendor_id IS NULL THEN
    INSERT INTO public.vendors (name, domain, support_email)
      VALUES (v_vendor_name, v_vendor_domain, v_support_email)
      RETURNING id INTO v_vendor_id;
  ELSE
    UPDATE public.vendors SET
      name = COALESCE(v_vendor_name, name),
      domain = COALESCE(v_vendor_domain, domain),
      support_email = COALESCE(v_support_email, support_email)
    WHERE id = v_vendor_id;
  END IF;

  SELECT id INTO v_existing_document_id FROM public.documents WHERE fingerprint = v_fingerprint LIMIT 1;
  IF v_existing_document_id IS NULL THEN
    INSERT INTO public.documents (
      vendor_id, fingerprint, n8n_execution_id, invoice_number,
      total_amount, currency, received_at, raw_payload
    ) VALUES (
      v_vendor_id, v_fingerprint, v_n8n_execution_id, v_invoice_number,
      v_total_amount, v_currency, v_received_at, payload
    ) RETURNING id INTO v_document_id;
  ELSE
    v_document_id := v_existing_document_id;
    UPDATE public.documents SET
      vendor_id = v_vendor_id,
      n8n_execution_id = COALESCE(v_n8n_execution_id, n8n_execution_id),
      invoice_number = COALESCE(v_invoice_number, invoice_number),
      total_amount = v_total_amount,
      currency = v_currency,
      received_at = v_received_at,
      raw_payload = payload
    WHERE id = v_document_id;
  END IF;

  DELETE FROM public.line_items WHERE document_id = v_document_id;

  INSERT INTO public.line_items (
    document_id, vendor_id, position, description, clean_name,
    billing_type, billing_cycle, quantity, unit_price, total_price,
    currency, period_end, category, original_description, seat_count, tier, raw_metadata
  )
  SELECT
    v_document_id, v_vendor_id, (i.ordinality - 1), 
    COALESCE(nullif(trim(i.value->>'description'), ''), 'Item'),
    COALESCE(nullif(trim(i.value->>'cleanName'), ''), nullif(trim(i.value->>'description'), ''), 'Item'),
    CASE lower(COALESCE(i.value->>'billingType', 'one_time'))
      WHEN 'recurring' THEN 'recurring'::public.billing_type_enum
      WHEN 'usage_based' THEN 'usage_based'::public.billing_type_enum
      WHEN 'penalty' THEN 'penalty'::public.billing_type_enum
      ELSE 'one_time'::public.billing_type_enum
    END,
    nullif(trim(i.value->>'billingCycle'), ''),
    COALESCE((i.value->>'quantity')::numeric, 1),
    COALESCE((i.value->>'unitPrice')::numeric, 0),
    COALESCE((i.value->>'totalPrice')::numeric, 0),
    upper(COALESCE(nullif(trim(i.value->>'currency'), ''), v_currency)),
    nullif(i.value->>'periodEnd', '')::date,
    nullif(trim(i.value #>> '{metadata,category}'), ''),
    nullif(trim(i.value #>> '{metadata,originalDescription}'), ''),
    nullif(i.value #>> '{metadata,seatCount}', '')::integer,
    nullif(trim(i.value #>> '{metadata,tier}'), ''),
    COALESCE(i.value->'metadata', '{}'::jsonb)
  FROM jsonb_array_elements(COALESCE(payload->'items', '[]'::jsonb)) WITH ORDINALITY AS i;

  GET DIAGNOSTICS v_inserted_items = ROW_COUNT;

  RETURN jsonb_build_object(
    'status', 'ok',
    'vendor_id', v_vendor_id,
    'document_id', v_document_id,
    'fingerprint', v_fingerprint,
    'inserted_line_items', v_inserted_items,
    'is_new_document', v_existing_document_id IS NULL
  );
END;
$body$;

CREATE OR REPLACE FUNCTION public.acquire_pipeline_job(
  p_job_key text,
  p_attachment_id text DEFAULT NULL,
  p_payload jsonb DEFAULT '{}'::jsonb,
  p_workflow_name text DEFAULT 'n8n',
  p_stage text DEFAULT 'started'
)
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS
$body$
DECLARE
  v_job_id uuid;
  v_existing public.pipeline_jobs%rowtype;
BEGIN
  IF p_job_key IS NULL OR length(trim(p_job_key)) = 0 THEN
    RAISE EXCEPTION 'p_job_key is required';
  END IF;

  INSERT INTO public.pipeline_jobs (
    job_key, attachment_id, status, attempt_count,
    workflow_name, current_stage, locked_at, started_at, payload
  ) VALUES (
    trim(p_job_key), nullif(trim(p_attachment_id), ''), 'processing', 1,
    nullif(trim(p_workflow_name), ''), nullif(trim(p_stage), ''),
    now(), now(), COALESCE(p_payload, '{}'::jsonb)
  )
  ON CONFLICT (job_key) DO NOTHING
  RETURNING id INTO v_job_id;

  IF v_job_id IS NOT NULL THEN
    RETURN jsonb_build_object(
      'acquired', true, 'job_id', v_job_id,
      'job_key', trim(p_job_key), 'status', 'processing', 'reason', 'new_job_created'
    );
  END IF;

  SELECT * INTO v_existing FROM public.pipeline_jobs WHERE job_key = trim(p_job_key) LIMIT 1;

  RETURN jsonb_build_object(
    'acquired', false, 'job_id', v_existing.id,
    'job_key', v_existing.job_key, 'status', v_existing.status,
    'reason', 'job_already_exists', 'attempt_count', v_existing.attempt_count,
    'current_stage', v_existing.current_stage, 'locked_at', v_existing.locked_at,
    'finished_at', v_existing.finished_at
  );
END;
$body$;

CREATE OR REPLACE FUNCTION public.complete_pipeline_job(
  p_job_key text,
  p_fingerprint text DEFAULT NULL,
  p_result jsonb DEFAULT '{}'::jsonb,
  p_stage text DEFAULT 'completed'
)
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS
$body$
DECLARE v_job_id uuid;
BEGIN
  IF p_job_key IS NULL OR length(trim(p_job_key)) = 0 THEN
    RAISE EXCEPTION 'p_job_key is required';
  END IF;

  UPDATE public.pipeline_jobs SET
    status = 'succeeded',
    fingerprint = COALESCE(nullif(trim(p_fingerprint), ''), fingerprint),
    result = COALESCE(p_result, '{}'::jsonb),
    finished_at = now(),
    current_stage = nullif(trim(p_stage), ''),
    updated_at = now()
  WHERE job_key = trim(p_job_key)
  RETURNING id INTO v_job_id;

  IF v_job_id IS NULL THEN
    RAISE EXCEPTION 'No pipeline_jobs row found for job_key: %', p_job_key;
  END IF;

  RETURN jsonb_build_object(
    'status', 'ok', 'job_id', v_job_id,
    'job_key', trim(p_job_key), 'final_status', 'succeeded'
  );
END;
$body$;

CREATE OR REPLACE FUNCTION public.fail_pipeline_job(
  p_job_key text,
  p_error text,
  p_result jsonb DEFAULT '{}'::jsonb,
  p_stage text DEFAULT 'failed'
)
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS
$body$
DECLARE v_job_id uuid;
BEGIN
  IF p_job_key IS NULL OR length(trim(p_job_key)) = 0 THEN
    RAISE EXCEPTION 'p_job_key is required';
  END IF;

  UPDATE public.pipeline_jobs SET
    status = 'failed',
    last_error = nullif(trim(p_error), ''),
    result = COALESCE(p_result, '{}'::jsonb),
    finished_at = now(),
    current_stage = nullif(trim(p_stage), ''),
    updated_at = now()
  WHERE job_key = trim(p_job_key)
  RETURNING id INTO v_job_id;

  IF v_job_id IS NULL THEN
    RAISE EXCEPTION 'No pipeline_jobs row found for job_key: %', p_job_key;
  END IF;

  RETURN jsonb_build_object(
    'status', 'ok', 'job_id', v_job_id,
    'job_key', trim(p_job_key), 'final_status', 'failed'
  );
END;
$body$;

