const staticData = $getWorkflowStaticData('global');
const execId     = $execution.id;
const countKey   = `_pollCount_${execId}`;
const jobIdKey   = `_jobId_${execId}`;

const current  = staticData[countKey] || 0;
const inputJson = $input.item.json;

// Capture job ID on FIRST pass (when item still has it from Start AI Extraction)
// On loop-back passes, HTTP response may not carry it — static data does
if (!staticData[jobIdKey] && inputJson.id) {
  staticData[jobIdKey] = inputJson.id;
}

const jobId = staticData[jobIdKey];

if (!jobId) {
  throw new Error('No extraction job ID found — cannot poll');
}

if (current >= 15) {
  // Clean up scoped keys — don't leak static data
  delete staticData[countKey];
  delete staticData[jobIdKey];
  throw new Error(`Extraction timed out after ${15 * 5}s (15 polls)`);
}

staticData[countKey] = current + 1;

// Always re-inject id so it survives into Wait → HTTP chain
return [{ json: { ...inputJson, id: jobId, _pollCount: staticData[countKey] } }];

// Reset scoped counter — clean up static data for this execution
const staticData = $getWorkflowStaticData('global');
const execId     = $execution.id;

delete staticData[`_pollCount_${execId}`];
delete staticData[`_jobId_${execId}`];

// Pass ALL data through unchanged
return $input.all();

const crypto = require('crypto');

const VALID_CURRENCIES = new Set([
  'USD','EUR','GBP','CAD','AUD','JPY','CHF','CNY','HKD','SGD',
  'SEK','NOK','DKK','NZD','MXN','INR','BRL','ZAR','AED','SAR',
  'PLN','CZK','HUF','ILS'
]);

const LEGAL_SUFFIXES = /\b(llc|inc|ltd|limited|gmbh|bv|b\.?v\.?|corp|corporation|co|company|plc|sa|sarl|pte|pty)\b/gi;

function normalizeKey(key) {
  return String(key || '').replace(/[^a-zA-Z0-9]/g, '').toLowerCase();
}

function findDeep(obj, targetKeys, depth = 0) {
  if (depth > 8 || obj == null) return null;

  const normalizedTargets = targetKeys.map(normalizeKey);

  if (Array.isArray(obj)) {
    for (const item of obj) {
      const found = findDeep(item, targetKeys, depth + 1);
      if (found !== null && found !== undefined) return found;
    }
    return null;
  }

  if (typeof obj !== 'object') return null;

  // Check current level first
  for (const [key, value] of Object.entries(obj)) {
    if (normalizedTargets.includes(normalizeKey(key)) && value !== null && value !== undefined) {
      return value;
    }
  }

  // Then recurse
  for (const [key, value] of Object.entries(obj)) {
    if (['metadata'].includes(String(key).toLowerCase())) continue;
    const found = findDeep(value, targetKeys, depth + 1);
    if (found !== null && found !== undefined) return found;
  }

  return null;
}

function parseNumber(value) {
  if (value == null) return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;

  const cleaned = String(value)
    .replace(/[^0-9.,-]/g, '')
    .replace(/,(?=\d{3}\b)/g, '') // remove thousand separators
    .replace(/,/g, '.');

  const num = Number(cleaned);
  return Number.isFinite(num) ? num : null;
}

function normalizeCurrency(value) {
  let curr = String(value || '').trim().toUpperCase();
  if (!VALID_CURRENCIES.has(curr)) return 'USD';
  return curr;
}

function normalizeDate(value) {
  if (!value) return null;
  const d = new Date(value);
  if (isNaN(d.getTime())) return null;
  return d.toISOString();
}

function normalizeDomain(value) {
  if (!value) return null;

  let domain = String(value).trim().toLowerCase();

  // If email, take domain part
  if (domain.includes('@')) {
    domain = domain.split('@').pop();
  }

  domain = domain
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .split('/')[0]
    .split('?')[0]
    .split('#')[0]
    .trim();

  if (!domain || !domain.includes('.')) return null;
  return domain;
}

function inferDomain(vendorName, supportEmail, explicitDomain, documentText) {
  const direct =
    normalizeDomain(explicitDomain) ||
    normalizeDomain(supportEmail);

  if (direct) return direct;

  // Try to find a domain in the text
  const urlMatch = String(documentText || '').match(/\b(?:https?:\/\/)?(?:www\.)?([a-z0-9-]+\.[a-z]{2,})(?:\/[^\s]*)?\b/i);
  if (urlMatch && urlMatch[1]) {
    return normalizeDomain(urlMatch[1]);
  }

  // Heuristic fallback from vendor name: "Calendly LLC" -> "calendly.com"
  let clean = String(vendorName || '')
    .toLowerCase()
    .replace(LEGAL_SUFFIXES, '')
    .replace(/[^a-z0-9\s-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!clean) return 'unknown.com';

  const slug = clean.replace(/\s+/g, '');
  if (slug) return `${slug}.com`;

  return 'unknown.com';
}

function getDocumentText(raw) {
  const sectionText = Array.isArray(raw.sections)
    ? raw.sections.map(s => s?.text).filter(Boolean).join('\n\n')
    : '';

  return sectionText || raw.summaryText || '';
}

function extractAmountFromText(documentText, labelPatterns) {
  const text = String(documentText || '');

  for (const pattern of labelPatterns) {
    const match = text.match(pattern);
    if (match && match[1] != null) {
      const parsed = parseNumber(match[1]);
      if (parsed !== null) return parsed;
    }
  }
  return null;
}

function inferBillingCycle(desc, metadataCycle, periodStart, periodEnd, documentText) {
  const raw = String(metadataCycle || desc || documentText || '').toLowerCase();

  if (raw.includes('month')) return 'monthly';
  if (raw.includes('annual') || raw.includes('year')) return 'annual';
  if (raw.includes('quarter')) return 'quarterly';
  if (raw.includes('week')) return 'weekly';
  if (raw.includes('day')) return 'daily';

  if (periodStart && periodEnd) {
    const start = new Date(periodStart);
    const end = new Date(periodEnd);
    if (!isNaN(start.getTime()) && !isNaN(end.getTime())) {
      const diffDays = Math.round((end - start) / (1000 * 60 * 60 * 24));
      if (diffDays >= 27 && diffDays <= 32) return 'monthly';
      if (diffDays >= 80 && diffDays <= 100) return 'quarterly';
      if (diffDays >= 360 && diffDays <= 370) return 'annual';
    }
  }

  return null;
}

function inferBillingType(li, desc, amount) {
  const rawType = String(
    li?.billingType ||
    li?.billing_type ||
    li?.type ||
    ''
  ).toLowerCase();

  const text = String(desc || '').toLowerCase();

  if (rawType.includes('usage')) return 'usage_based';
  if (rawType.includes('penalty')) return 'penalty';
  if (rawType.includes('recur')) return 'recurring';

  if (amount < 0) return 'one_time';
  if (text.includes('monthly') || text.includes('annual') || text.includes('subscription') || text.includes('plan')) {
    return 'recurring';
  }

  return 'one_time';
}

function inferCategory(li, desc, vendorName, documentText) {
  if (li?.category) return li.category;

  const text = `${desc || ''} ${vendorName || ''} ${documentText || ''}`.toLowerCase();

  if (text.includes('tax') || text.includes('vat') || text.includes('btw')) return 'Tax';
  if (text.includes('discount') || text.includes('coupon') || text.includes('credit')) return 'Discount';
  if (text.includes('payment')) return 'Payment';
  if (text.includes('subscription') || text.includes('monthly') || text.includes('annual') || text.includes('saas')) {
    return 'SaaS License';
  }

  return 'Uncategorized';
}

return $input.all().map((item) => {
  try {
    const raw = item.json || {};

    // Support multiple possible LLM output shapes
    const invoice =
      raw.output?.extracted ||
      raw.extracted ||
      raw.data ||
      raw;

    const documentText = getDocumentText(raw);

    // ==========================================
    // 1. ROOT EXTRACTION
    // ==========================================
    const invNumber =
      findDeep(invoice, ['invoiceNumber', 'InvoiceNumber', 'invoice_number', 'receipt_number', 'id']) ||
      'NOT_EXTRACTED';

    const vendorName =
      invoice.merchant?.name ||
      findDeep(invoice, ['merchantName', 'vendorName', 'name']) ||
      'Unknown Vendor';

    const supportEmail =
      invoice.merchant?.supportEmail ||
      findDeep(invoice, ['supportEmail', 'support_email', 'email']) ||
      null;

    const explicitDomain =
      invoice.merchant?.domain ||
      findDeep(invoice, ['domain', 'website', 'url']) ||
      null;

    const vendorDomain = inferDomain(vendorName, supportEmail, explicitDomain, documentText);

    const currRaw =
      findDeep(invoice, ['currency', 'Currency']) ||
      'USD';

    const currency = normalizeCurrency(currRaw);

    const rawDate =
      findDeep(invoice, ['datePaid', 'dateIssued', 'invoiceDate', 'date', 'created_at']) ||
      Date.now();

    const receivedAt = normalizeDate(rawDate) || new Date().toISOString();

    const isPaid =
      raw.isPaid ??
      invoice.isPaid ??
      /(?:\bpaid\b|amount due.*?0\.00|payments?\s*\()/i.test(documentText);

    // Explicit monetary values
    const explicitTotal =
      parseNumber(findDeep(invoice, ['totalAmount', 'invoiceAmount', 'total'])) ??
      extractAmountFromText(documentText, [
        /Invoice Amount\s*[$€£]?\s*([0-9,]+(?:\.[0-9]{2})?)/i,
        /Total\s*[$€£]?\s*([0-9,]+(?:\.[0-9]{2})?)/i
      ]) ??
      0;

    const amountDue =
      parseNumber(findDeep(invoice, ['amountDue', 'amount_due', 'balanceDue'])) ??
      extractAmountFromText(documentText, [
        /Amount Due(?:\s*\([A-Z]{3}\))?\s*[$€£]?\s*([0-9,]+(?:\.[0-9]{2})?)/i
      ]) ??
      null;

    const nextRenewalDate =
      findDeep(invoice, ['nextRenewalDate', 'NextRenewalDate', 'renewal_date', 'nextBillingDate']) ||
      extractAmountFromText(documentText, []) || null;

    // ==========================================
    // 2. FINGERPRINT
    // ==========================================
    let fingerprint = raw.fingerprint || null;

    if (!fingerprint) {
      try {
        fingerprint = $('Merge Metadata and Identity').first().json.fingerprint;
      } catch (e) {}
    }

    if (!fingerprint) {
      const uniqueString = `${vendorName}-${invNumber}-${receivedAt}`.toLowerCase().trim();
      fingerprint = crypto.createHash('sha256').update(uniqueString).digest('hex');
    }

    let execId = 'manual-run';
    try {
      execId = String($execution.id);
    } catch (e) {}

    // ==========================================
    // 3. LINE ITEM MAPPING
    // ==========================================
    const sourceItems = Array.isArray(invoice.items) ? invoice.items : [];

    const mappedItems = sourceItems.map((li) => {
      const desc =
        findDeep(li, ['cleanName', 'description', 'name', 'item_desc']) ||
        'Item';

      const quantity =
        parseNumber(findDeep(li, ['quantity', 'qty', 'count'])) ?? 1;

      const unitPrice =
        parseNumber(findDeep(li, ['unitPrice', 'price', 'rate'])) ?? 0;

      const amount =
        parseNumber(findDeep(li, ['amount', 'totalPrice', 'total'])) ??
        (quantity * unitPrice);

      const periodStart = li?.period?.start || null;
      const periodEnd =
        li?.period?.end ||
        findDeep(invoice, ['nextRenewalDate', 'NextRenewalDate', 'nextBillingDate']) ||
        null;

      const billingCycle = inferBillingCycle(
        desc,
        li?.metadata?.billingCycle || li?.metadata?.billing_cycle,
        periodStart,
        periodEnd,
        documentText
      );

      const billingType = inferBillingType(li, desc, amount);
      const category = inferCategory(li, desc, vendorName, documentText);

      return {
        description: desc,
        cleanName: findDeep(li, ['cleanName']) || desc,
        billingType,
        billingCycle,
        quantity: Number(quantity) || 1,
        unitPrice: Number(unitPrice) || 0,
        totalPrice: Number(amount) || 0,
        currency,
        periodEnd: periodEnd || null,
        metadata: {
          category,
          originalDescription: li?.description || desc,
          seatCount: li?.metadata?.seatCount ?? li?.metadata?.seat_count ?? null,
          tier: li?.metadata?.tier ?? null
        }
      };
    });

    // ==========================================
    // 4. ADD NEGATIVE PAYMENT LINE ITEM IF PAID
    // ==========================================
    const alreadyHasPaymentLine = mappedItems.some(li =>
      String(li.description || '').toLowerCase().includes('payment') ||
      String(li.metadata?.category || '').toLowerCase() === 'payment'
    );

    let paymentAmount =
      extractAmountFromText(documentText, [
        /Payments?\s*\(\s*[$€£]?\s*([0-9,]+(?:\.[0-9]{2})?)\s*\)/i,
        /paid on .*?[$€£]?\s*([0-9,]+(?:\.[0-9]{2})?)/i
      ]);

    if (paymentAmount == null && isPaid && explicitTotal > 0) {
      paymentAmount = explicitTotal;
    }

    if (isPaid && paymentAmount && !alreadyHasPaymentLine) {
      mappedItems.push({
        description: 'Payment Applied',
        cleanName: 'Payment Applied',
        billingType: 'one_time',
        billingCycle: null,
        quantity: 1,
        unitPrice: -Math.abs(paymentAmount),
        totalPrice: -Math.abs(paymentAmount),
        currency,
        periodEnd: null,
        metadata: {
          category: 'Payment',
          originalDescription: 'Auto-generated negative payment line from paid invoice'
        }
      });
    }

    // ==========================================
    // 5. TOTAL AMOUNT FOR SPEND TRACKING
    // We prefer actual spend / positive service charges over "amount due"
    // ==========================================
    const positiveLineTotal = mappedItems
      .filter(li => Number(li.totalPrice) > 0)
      .reduce((sum, li) => sum + Number(li.totalPrice || 0), 0);

    const totalAmount =
      positiveLineTotal > 0
        ? positiveLineTotal
        : (explicitTotal > 0 ? explicitTotal : (amountDue ?? 0));

    // ==========================================
    // 6. FINAL PAYLOAD
    // ==========================================
    return {
      json: {
        fingerprint,
        n8nExecutionId: execId,
        vendorName,
        vendorDomain,
        supportEmail,
        invoiceNumber: invNumber,
        totalAmount: Number(totalAmount) || 0,
        currency,
        receivedAt,
        items: mappedItems
      }
    };

  } catch (error) {
    return {
      json: {
        _error: true,
        message: error.message,
        stack: error.stack
      }
    };
  }
});
